import React, { useEffect, useState } from 'react'

export default function Practice() {
    let [count,setCount]=useState(0)
    console.log(count)
    useEffect(()=>{
        console.log('from here',count)
    },[count])
  return (
    <div>

        <button onClick={()=>setCount(count+1)}>Click here</button>

    </div>
  )
}
